        UPDATE STORE S
        SET S.RATING = (
            SELECT NVL(ROUND(AVG(UR.RATING), 1), 0)
            FROM USER_REVIEW UR
            INNER JOIN RESERVATION R ON UR.RESERV_ID = R.RESERV_ID
		WHERE R.STORE_ID = #{value}
              AND UR.STATUS = '정상'
        ),
        S.REVIEW_COUNT = (
            SELECT COUNT(*)
            FROM USER_REVIEW UR
            INNER JOIN RESERVATION R ON UR.RESERV_ID = R.RESERV_ID
		WHERE R.STORE_ID = #{value}
              AND UR.STATUS = '정상'
        )
		WHERE S.STORE_ID = #{value}

mapper.select:
SELECT STORE_ID
FROM RESERVATION
WHERE RESERV_ID = #{reservId}
  AND USER_ID = #{userId}

	SELECT USER_ID AS userId, STORE_ID AS storeId
    FROM RESERVATION
	WHERE RESERV_ID = #{value}

SELECT COUNT(*)
FROM USER_REVIEW UR
INNER JOIN RESERVATION R ON UR.RESERV_ID = R.RESERV_ID
WHERE R.USER_ID = #{userId}
  AND R.STORE_ID = #{storeId}
  AND UR.STATUS = '정상'
  AND UR.CREATE_DATE >= #{startDate}
